const body = $input.item.json.body || $input.item.json;
const url = (body.url || '').toString().trim();
if (!/^https?:\/\/.+/.test(url)) throw new Error('URL invalide – doit commencer par http:// ou https://');
if (url.length > 2000) throw new Error('URL trop longue');
const clean = s => (s || '').toString().replace(/<[^>]*>/g, '').replace(/ignore\s+(all|previous|above)/gi, '').trim().substring(0, 300);
return { url, contexte: clean(body.contexte || body.note || '') };

const html = ($input.item.json.data || '').toString();
const url = $('Valider et sécuriser').item.json.url;
const contexte = $('Valider et sécuriser').item.json.contexte;

// Extraire le titre
const titleMatch = html.match(/<title[^>]*>([^<]+)<\/title>/i);
const titre = (titleMatch ? titleMatch[1] : url).trim().substring(0, 200);

// Extraire le texte principal (heuristique : strip HTML tags)
const texte = html
  .replace(/<script[\s\S]*?<\/script>/gi, '')
  .replace(/<style[\s\S]*?<\/style>/gi, '')
  .replace(/<nav[\s\S]*?<\/nav>/gi, '')
  .replace(/<footer[\s\S]*?<\/footer>/gi, '')
  .replace(/<header[\s\S]*?<\/header>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/\s{2,}/g, ' ')
  .trim()
  .substring(0, 4000);

return { url, contexte, titre, texte };

const content = $input.item.json.message.content;
const src = $('Extraire texte').item.json;
let ai;
try {
  const match = content.match(/\{[\s\S]*\}/);
  ai = JSON.parse(match[0]);
} catch(e) {
  ai = { titre_clean: src.titre, resume: src.texte.substring(0, 500), points_cles: [], tags: [], interet: 'moyen', action_suggérée: 'À lire' };
}
return {
  url: src.url,
  contexte: src.contexte,
  titre: ai.titre_clean || src.titre,
  resume: ai.resume || '',
  points_cles: JSON.stringify(ai.points_cles || []),
  tags: JSON.stringify(ai.tags || []),
  interet: ai.interet || 'moyen',
  action: ai.action_suggérée || ''
};
